    56→static void test_representative_100(void)
    57→{
    58→    /* --- Section 1: Special IEEE 754 values (7) --- */
    59→    emit(0.0);
    60→    emit(-0.0);
    61→    emit_u(0x7ff8000000000000ULL);  /* qNaN */
    62→    emit_u(0x7ff0000000000001ULL);  /* sNaN */
    63→    emit_u(0xfff8000000000000ULL);  /* -qNaN */
    64→    emit_u(0x7ff0000000000000ULL);  /* +Inf */
    65→    emit_u(0xfff0000000000000ULL);  /* -Inf */
    66→
    67→    /* --- Section 2: Subnormal (denormal) values (6) --- */
    68→    emit_u(0x0000000000000001ULL);  /* min positive subnormal: 2^-1074 */
    69→    emit_u(0x8000000000000001ULL);  /* min negative subnormal */
    70→    emit_u(0x0008000000000000ULL);  /* mid positive subnormal */
    71→    emit_u(0x8008000000000000ULL);  /* mid negative subnormal */
    72→    emit_u(0x000fffffffffffffULL);  /* max positive subnormal: just below DBL_MIN */
    73→    emit_u(0x800fffffffffffffULL);  /* max negative subnormal */
    74→
    75→    /* --- Section 3: Normal boundary values (4) --- */
    76→    emit(DBL_MIN);   /* smallest positive normal: 2^-1022 = 0x0010000000000000 */
    77→    emit(-DBL_MIN);
    78→    emit(DBL_MAX);   /* largest finite double: 0x7fefffffffffffff */
    79→    emit(-DBL_MAX);
    80→
    81→    /* --- Section 4: Exact half-integers (round-to-even stress) (14) --- */
    82→    emit(0.5);    /* rounds to 0.0 (even) */
    83→    emit(-0.5);   /* rounds to -0.0 (even) */
    84→    emit(1.5);    /* rounds to 2.0 (even) */
    85→    emit(-1.5);   /* rounds to -2.0 (even) */
    86→    emit(2.5);    /* rounds to 2.0 (even) */
    87→    emit(-2.5);   /* rounds to -2.0 (even) */
    88→    emit(3.5);    /* rounds to 4.0 (even) */
    89→    emit(-3.5);   /* rounds to -4.0 (even) */
    90→    emit(4.5);    /* rounds to 4.0 (even) */
    91→    emit(-4.5);   /* rounds to -4.0 (even) */
    92→    emit(5.5);    /* rounds to 6.0 (even) */
    93→    emit(-5.5);   /* rounds to -6.0 (even) */
    94→    emit(100.5);  /* rounds to 100.0 (even) */
    95→    emit(-100.5); /* rounds to -100.0 (even) */
