    98→    emit_u(0x3fdffffffffffffeULL);  /* one ULP below 0.5 */
    99→    emit_u(0x3fe0000000000000ULL);  /* exactly 0.5 (already done above; distinct bit pattern ref) */
   100→    emit_u(0x3fe0000000000001ULL);  /* one ULP above 0.5 */
   101→    emit_u(0xbfdffffffffffffeULL);  /* one ULP toward zero from -0.5 */
   102→    emit_u(0x3ff7ffffffffffffULL);  /* one ULP below 1.5 */
   103→    emit_u(0x3ff8000000000000ULL);  /* exactly 1.5 (bit pattern: 1.5) */
   104→    emit_u(0x3ff8000000000001ULL);  /* one ULP above 1.5 */
   105→    emit_u(0xbff8000000000001ULL);  /* one ULP away from zero from -1.5 */
