   135→    emit(-3.0);
   136→    emit(1.0000000000000002);   /* 1.0 + 1 ULP: 0x3ff0000000000001 */
   137→    emit(-1.0000000000000002);  /* -(1.0 + 1 ULP) */
   138→    emit(0.9999999999999999);   /* 1.0 - 1 ULP: 0x3fefffffffffffff */
   139→    emit(-0.9999999999999999);  /* -(1.0 - 1 ULP) */
