   142→    /* 2^52 = 4503599627370496.0: all doubles >= 2^52 are exact integers */
   143→    emit_u(0x4330000000000000ULL);  /* 2^52: smallest double with no fractional part */
   144→    emit_u(0x4330000000000001ULL);  /* 2^52 + 1 ULP */
